        // ── Mapping clé → SVG string ───────────────────────────────────────

        private static readonly Dictionary<string, string> _svgMap = new(StringComparer.OrdinalIgnoreCase)
        {
            ["OldProfile"]      = OldProfile,
            ["Desktop"]         = Desktop,
            ["Documents"]       = Documents,
            ["ExcelMacros"]     = ExcelMacros,
            ["Pictures"]        = Pictures,
            ["NetworkDrives"]   = NetworkDrives,
            ["OfficeTemplates"] = OfficeTemplates,
            ["Music"]           = Music,
            ["OneNote"]         = OneNote,
            ["Public"]          = Public,
            ["StickyNotes"]     = StickyNotes,
            ["Downloads"]       = Downloads,
            ["Videos"]          = Videos,
            ["Wallpaper"]       = Wallpaper,
        };

        // ── Cache Bitmap (clé + taille + couleur) ──────────────────────────
        // La couleur fait partie de la clé afin de respecter les changements de thème.
        private static readonly Dictionary<(string key, int size, int rgb), Bitmap> _cache = new();

        /// <summary>
        /// Retourne un Bitmap rendu du SVG associé à la clé, à la taille indiquée.
        /// Retourne null si la clé n'a pas de SVG associé.
        /// Le bitmap est mis en cache — ne pas disposer.
        /// </summary>
        public static Bitmap? Get(string key, int size, Color fillColor)
        {
            int rgb      = (fillColor.R << 16) | (fillColor.G << 8) | fillColor.B;
            var cacheKey = (key, size, rgb);
            if (_cache.TryGetValue(cacheKey, out var cached))
                return cached;

            if (!_svgMap.TryGetValue(key, out var svgSource))
                return null;

            try
            {
                // Remplace le placeholder de couleur par la couleur réelle
                string hex    = $"#{fillColor.R:X2}{fillColor.G:X2}{fillColor.B:X2}";
                string svgText = svgSource.Replace("#currentFill", hex);

                using var stream = new MemoryStream(System.Text.Encoding.UTF8.GetBytes(svgText));
                var doc = SvgDocument.Open<SvgDocument>(stream);
                doc.Width  = new SvgUnit(SvgUnitType.Pixel, size);
                doc.Height = new SvgUnit(SvgUnitType.Pixel, size);

                var bmp = doc.Draw(size, size);
                _cache[cacheKey] = bmp;
                return bmp;
            }
            catch
            {
                return null;
            }
        }

        /// <summary>Vide le cache (à appeler lors d'un changement de thème).</summary>
        public static void ClearCache() => _cache.Clear();

        /// <summary>Retourne true si une icône SVG existe pour cette clé.</summary>
        public static bool Has(string key) => _svgMap.ContainsKey(key);
    }
